  static async create(ptr: string, transferType: transferType): Promise<GstBaseByteWriter> {
    const instance = new GstBaseByteWriter(ptr, transferType);
    if (transferType === 'full')
      gstbasebytewriterRegistry.register(instance, ptr);
    return instance;
  }
    







 
